import React, { useCallback, useMemo, useRef, useState } from 'react';
import {
  Button,
  Input,
  Modal,
  Tabs,
  TextArea,
  SearchTextInput,
  dispatchAppToast,
  LeaveConfirmModal,
  useDirtyTracking,
  useLeaveConfirm,
  useViewMobileLayout,
  type Tab,
} from '@linm-soft-org/linm-web-common-components';
import { useAppDispatch } from '../../../store/hooks';
import { useCatalogListSelection } from '../../../hooks/useCatalogListSelection';
import { useCatalogListPermissions } from '../../../hooks/useCatalogListPermissions';
import { masterService } from '../../../services/master/masterService';
import type { AssetLookupDto } from '../../../services/master/models';
import { normalizeCode } from '../../../utils/codeField';
import { scrollToFirstFieldError } from '../../../utils/catalogFormValidation';
import {
  getErpListRowMenuHint,
  catalogListRowMenuHintDismissStorageKey,
} from '../../../utils/catalogListRowMenuHint';
import {
  CatalogFormFooter,
  useCatalogPagination,
  useServerPagedListLoading,
  CatalogListHeaderFilters,
  CatalogListMasterLinPageLayout,
  CatalogListPageTabs,
  CatalogRowActionMenu,
  type CatalogRowMenuAction,
  type CatalogListToolbarBridge,
} from '../../../components/catalog';
import {
  CatalogListGridFromSchema,
  CatalogUiSchemaEditorModal,
  useCatalogUiSchema,
  listVisibleFields,
} from '../../../components/catalog/catalogUiSchema';
import type { CatalogBatchDeleteMode } from '../../../components/catalog';
import styles from '../../../styles/erpPage.module.css';

const TEST_ID = 'dm-ho-tro-tscd';

type FormErrors = Partial<Record<'code' | 'name', string>>;

type AssetLookupGridRow = Omit<AssetLookupDto, 'id'> & {
  id: string;
  lookupId: string;
};

type TabKey = 'assetCategories' | 'capitalSources' | 'increaseReasons' | 'decreaseReasons';

const PAGE_TABS: Tab[] = [
  { id: 'assetCategories', label: 'Loại TSCĐ' },
  { id: 'capitalSources', label: 'Nguồn vốn' },
  { id: 'increaseReasons', label: 'Lý do tăng' },
  { id: 'decreaseReasons', label: 'Lý do giảm' },
];

const TAB_META: Record<TabKey, { title: string; label: string }> = {
  assetCategories: { label: 'Loại TSCĐ', title: 'Loại tài sản cố định' },
  capitalSources: { label: 'Nguồn vốn', title: 'Nguồn vốn hình thành TSCĐ' },
  increaseReasons: { label: 'Lý do tăng', title: 'Lý do tăng TSCĐ' },
  decreaseReasons: { label: 'Lý do giảm', title: 'Lý do giảm TSCĐ' },
};

const TAB_CATALOG_KIND: Record<TabKey, string> = {
  assetCategories: 'asset-categories',
  capitalSources: 'capital-sources',
  increaseReasons: 'increase-reasons',
  decreaseReasons: 'decrease-reasons',
};

const HoTroTscdPage: React.FC = () => {
  const dispatch = useAppDispatch();
  const viewMobile = useViewMobileLayout();
  const toolbarBridgeRef = useRef<CatalogListToolbarBridge | null>(null);
  const [rowMenu, setRowMenu] = useState<{ x: number; y: number; row: AssetLookupGridRow } | null>(null);
  const { onDirtyChange, guardedNavigate, leaveConfirmModalProps } = useLeaveConfirm({
    message: 'Có thay đổi chưa được lưu. Đóng form sẽ mất dữ liệu đã nhập.',
  });
  const { markDirty, markClean } = useDirtyTracking(onDirtyChange);
  const [tab, setTab] = useState<TabKey>('assetCategories');
  const [items, setItems] = useState<AssetLookupDto[]>([]);
  const sessionCompanyName = useMemo(() => items[0]?.companyName, [items]);
  const [modalOpen, setModalOpen] = useState(false);
  const [editing, setEditing] = useState<AssetLookupDto | null>(null);
  const [formViewOnly, setFormViewOnly] = useState(false);
  const [form, setForm] = useState<Partial<AssetLookupDto>>({ isActive: true });
  const [errors, setErrors] = useState<FormErrors>({});
  const [saving, setSaving] = useState(false);
  const [reloadKey, setReloadKey] = useState(0);
  const [schemaEditorOpen, setSchemaEditorOpen] = useState(false);
  const [searchDraft, setSearchDraft] = useState('');
  const [search, setSearch] = useState('');

  const catalogKind = TAB_CATALOG_KIND[tab];
  const apiType = tab;
  const { canWrite } = useCatalogListPermissions(catalogKind);
  const { schema, reload: reloadSchema } = useCatalogUiSchema(catalogKind);
  const listColumns = useMemo(() => listVisibleFields(schema), [schema]);

  const tabMeta = TAB_META[tab];
  const filteredItems = useMemo(() => {
    const q = search.trim().toLowerCase();
    if (!q) return items;
    return items.filter(
      r => r.code.toLowerCase().includes(q)
        || r.name.toLowerCase().includes(q)
        || (r.note?.toLowerCase().includes(q) ?? false),
    );
  }, [items, search]);
  const { page, setPage, pageItems, totalCount, pageSize, setPageSize, resetPage } = useCatalogPagination(filteredItems);
  const {
    showTableLoading,
    pageLoading,
    setLoadingMode,
    beginFetch,
    endFetch,
  } = useServerPagedListLoading();

  const gridRows = useMemo<AssetLookupGridRow[]>(
    () => pageItems.map(r => {
      const { id, ...rest } = r;
      return { ...rest, lookupId: String(id), id: String(id) };
    }),
    [pageItems],
  );

  const selection = useCatalogListSelection({
    rows: gridRows,
    totalCount,
    page,
    pageSize,
    getRowId: r => r.id,
    isRowSelectable: () => true,
  });

  const refresh = () => {
    setLoadingMode('filter');
    selection.clearSelection();
    setReloadKey(k => k + 1);
  };

  React.useEffect(() => {
    let cancelled = false;
    beginFetch();
    const t = setTimeout(() => {
      masterService.getAssetLookup(apiType)
        .then(data => { if (!cancelled) setItems(data); })
        .catch(err => {
          if (!cancelled) dispatchAppToast(dispatch, { message: err?.message ?? 'Lỗi tải danh mục TSCĐ', type: 'error' });
        })
        .finally(() => { if (!cancelled) endFetch(); });
    }, 0);
    return () => { cancelled = true; clearTimeout(t); };
  }, [apiType, reloadKey, dispatch]);

  const clearFieldError = (key: keyof FormErrors) => {
    setErrors(prev => {
      if (!prev[key]) return prev;
      const next = { ...prev };
      delete next[key];
      return next;
    });
  };

  const validate = (): FormErrors => {
    const next: FormErrors = {};
    if (!form.code?.trim()) next.code = 'Nhập mã';
    if (!form.name?.trim()) next.name = 'Nhập tên';
    return next;
  };

  const closeFormModal = () => {
    guardedNavigate(() => {
      setModalOpen(false);
      setFormViewOnly(false);
      markClean();
    });
  };

  const openAdd = () => {
    setEditing(null);
    setForm({ isActive: true });
    setErrors({});
    setFormViewOnly(false);
    markClean();
    setModalOpen(true);
  };

  const openView = useCallback((row: AssetLookupGridRow) => {
    const { id: _gridId, lookupId, ...rest } = row;
    const dto: AssetLookupDto = { id: lookupId, ...rest };
    setEditing(dto);
    setForm({ ...dto });
    setErrors({});
    setFormViewOnly(true);
    markClean();
    setModalOpen(true);
  }, [markClean]);

  const openEdit = useCallback((row: AssetLookupGridRow) => {
    if (!canWrite) {
      openView(row);
      return;
    }
    const { id: _gridId, lookupId, ...rest } = row;
    const dto: AssetLookupDto = { id: lookupId, ...rest };
    setEditing(dto);
    setForm({ ...dto });
    setErrors({});
    setFormViewOnly(false);
    markClean();
    setModalOpen(true);
  }, [canWrite, markClean, openView]);

  const modalTitle = useMemo(() => {
    if (!editing) return `Thêm ${tabMeta.label}`;
    if (formViewOnly) return `Xem ${tabMeta.label}`;
    return `Sửa ${tabMeta.label}`;
  }, [editing, formViewOnly, tabMeta.label]);

  const handleSave = async () => {
    const nextErrors = validate();
    if (Object.keys(nextErrors).length > 0) {
      setErrors(nextErrors);
      scrollToFirstFieldError(TEST_ID);
      return;
    }
    setSaving(true);
    try {
      if (editing) await masterService.updateAssetLookup(apiType, editing.id, form);
      else await masterService.createAssetLookup(apiType, form);
      dispatchAppToast(dispatch, { message: editing ? 'Cập nhật thành công' : 'Tạo mới thành công', type: 'success' });
      markClean();
      setModalOpen(false);
      setFormViewOnly(false);
      refresh();
    } catch (err: unknown) {
      dispatchAppToast(dispatch, { message: err instanceof Error ? err.message : 'Lưu thất bại', type: 'error' });
    } finally {
      setSaving(false);
    }
  };

  const resolveDeleteIds = (): string[] => {
    if (selection.selectionMode === 'all') {
      return items.map(r => r.id);
    }
    return [...selection.selectedIds]
      .map(gridId => gridRows.find(r => r.id === gridId)?.lookupId)
      .filter((id): id is string => id != null);
  };

  const handleBatchDelete = async (mode: CatalogBatchDeleteMode) => {
    const ids = resolveDeleteIds();
    if (ids.length === 0) throw new Error('Không có bản ghi hợp lệ để xóa');
    if (mode === 'soft') {
      await Promise.all(ids.map(id => {
        const row = items.find(r => r.id === id)!;
        return masterService.updateAssetLookup(apiType, id, { ...row, isActive: false });
      }));
      dispatchAppToast(dispatch, { message: `Đã ngưng ${ids.length} mục`, type: 'success' });
    } else {
      await Promise.all(ids.map(id => masterService.deleteAssetLookup(apiType, id)));
      dispatchAppToast(dispatch, { message: `Đã xóa ${ids.length} mục`, type: 'success' });
    }
    refresh();
  };

  const handleTabChange = (id: string) => {
    const next = id as TabKey;
    setTab(next);
    setSearch('');
    setSearchDraft('');
    resetPage();
    selection.clearSelection();
    setRowMenu(null);
  };

  const rowMenuHintMessage = getErpListRowMenuHint(viewMobile);

  const handleRowOpenActionMenu = useCallback(
    ({ row, x, y }: { row: AssetLookupGridRow; x: number; y: number }) => {
      const showEdit = canWrite;
      const showView = !canWrite;
      const showDelete = canWrite;
      if (!showEdit && !showView && !showDelete) return;
      selection.selectActiveRow(row);
      setRowMenu({ x, y, row });
    },
    [canWrite, selection],
  );

  const handleRowMenuSelect = useCallback(
    (action: CatalogRowMenuAction) => {
      const row = rowMenu?.row;
      if (!row) return;
      switch (action) {
        case 'view':
          openView(row);
          break;
        case 'edit':
          openEdit(row);
          break;
        case 'delete': {
          if (!selection.isRowChecked(row)) {
            selection.toggleRow(row, true);
          }
          toolbarBridgeRef.current?.openDelete();
          break;
        }
        default:
          break;
      }
    },
    [rowMenu?.row, openEdit, openView, selection],
  );

  const rowMenuRow = rowMenu?.row;
  const rowMenuShowEdit = !!rowMenuRow && canWrite;
  const rowMenuShowView = !!rowMenuRow && !canWrite;
  const rowMenuShowDelete = !!rowMenuRow && canWrite;

  const tabsNode = (
    <CatalogListPageTabs data-testid={`${TEST_ID}-tabs`}>
      <Tabs
        tabs={PAGE_TABS}
        activeTab={tab}
        onTabChange={handleTabChange}
        variant="underline"
      />
    </CatalogListPageTabs>
  );

  return (
    <>
      <CatalogListMasterLinPageLayout
        testIdPrefix={TEST_ID}
        catalogKind={catalogKind}
        selection={selection}
        totalCount={totalCount}
        selectableOnPage={gridRows}
        onAdd={openAdd}
        onEdit={openEdit}
        onRefresh={refresh}
        onBatchDelete={handleBatchDelete}
        toolbarBridgeRef={toolbarBridgeRef}
        showSchemaConfig
        onOpenSchemaConfig={() => setSchemaEditorOpen(true)}
        page={page}
        pageSize={pageSize}
        onPageChange={p => { setPage(p); selection.clearSelection(); }}
        onPageSizeChange={size => { setLoadingMode('filter'); setPageSize(size); }}
        showTableLoading={showTableLoading}
        pageLoading={pageLoading}
        header={{ title: 'Hỗ trợ TSCĐ', titleIconClass: 'fas fa-landmark', subTitle: tabMeta.title }}
        listTitle={tabMeta.title}
        listRowMenuHelp
        topChrome={tabsNode}
        filters={(
          <CatalogListHeaderFilters testIdPrefix={TEST_ID}>
            <div className={styles.field} data-testid={`${TEST_ID}-field-search`}>
              <SearchTextInput
                label="Tìm kiếm"
                placeholder="Tìm mã, tên..."
                value={searchDraft}
                onChange={setSearchDraft}
                onSearch={() => {
                  setSearch(searchDraft.trim());
                  resetPage();
                  selection.clearSelection();
                }}
                testId={`${TEST_ID}-search-text`}
              />
            </div>
          </CatalogListHeaderFilters>
        )}
        schemaEditorModal={(
          <CatalogUiSchemaEditorModal
            testIdPrefix={TEST_ID}
            catalogKind={catalogKind}
            isOpen={schemaEditorOpen}
            onClose={() => setSchemaEditorOpen(false)}
            onSaved={() => {
              reloadSchema();
              refresh();
            }}
          />
        )}
        extraModals={(
          <>
            <CatalogRowActionMenu
              open={rowMenu != null}
              x={rowMenu?.x ?? 0}
              y={rowMenu?.y ?? 0}
              onClose={() => setRowMenu(null)}
              onSelect={handleRowMenuSelect}
              testIdPrefix={TEST_ID}
              showEdit={rowMenuShowEdit}
              showView={rowMenuShowView}
              showHistory={false}
              showRename={false}
              showDelete={rowMenuShowDelete}
            />
            <LeaveConfirmModal {...leaveConfirmModalProps} />
          </>
        )}
      >
        {gridRows.length === 0 ? (
          <div className={styles.empty}><i className="fas fa-inbox" /><p>Không có dữ liệu</p></div>
        ) : listColumns.length > 0 ? (
          <CatalogListGridFromSchema
            testIdPrefix={TEST_ID}
            rows={gridRows}
            page={page}
            pageSize={pageSize}
            columns={listColumns}
            schema={schema}
            selection={selection}
            getRowId={r => r.id}
            isRowSelectable={() => true}
            onRowOpenActionMenu={handleRowOpenActionMenu}
            rowMenuHintMessage={rowMenuHintMessage}
            rowMenuHintDismissStorageKey={catalogListRowMenuHintDismissStorageKey(TEST_ID)}
            enableRowMenuLongPress={viewMobile}
          />
        ) : null}
      </CatalogListMasterLinPageLayout>

      <Modal isOpen={modalOpen} onClose={closeFormModal} title={modalTitle}>
        <div className={styles.modalBody} data-testid={`${TEST_ID}-form`}>
          <div className={styles.formGrid}>
            <div className={styles.masterCodeNameRow}>
              <div className={styles.field} data-testid={`${TEST_ID}-field-code`}>
                <label className={styles.label}>Mã *</label>
                <Input
                  value={form.code ?? ''}
                  readOnly={formViewOnly || !!editing}
                  error={errors.code}
                  className={styles.codeInput}
                  onChange={e => {
                    markDirty();
                    clearFieldError('code');
                    setForm(f => ({ ...f, code: normalizeCode(e.target.value) }));
                  }}
                />
              </div>
              <div className={styles.field} data-testid={`${TEST_ID}-field-name`}>
                <label className={styles.label}>Tên *</label>
                <Input
                  value={form.name ?? ''}
                  readOnly={formViewOnly}
                  error={errors.name}
                  onChange={e => {
                    markDirty();
                    clearFieldError('name');
                    setForm(f => ({ ...f, name: e.target.value }));
                  }}
                />
              </div>
            </div>
            <div className={styles.field} style={{ gridColumn: '1 / -1' }} data-testid={`${TEST_ID}-field-note`}>
              <label className={styles.label}>Ghi chú</label>
              <TextArea
                rows={3}
                readOnly={formViewOnly}
                value={form.note ?? ''}
                onChange={e => {
                  markDirty();
                  setForm(f => ({ ...f, note: e.target.value }));
                }}
              />
            </div>
          </div>
          {formViewOnly ? (
            <div className={styles.modalActions}>
              <Button variant="secondary" onClick={closeFormModal}>Đóng</Button>
            </div>
          ) : (
            <CatalogFormFooter
              companyName={editing?.companyName ?? sessionCompanyName}
              testIdPrefix={TEST_ID}
              checked={form.isActive ?? true}
              onActiveChange={c => {
                markDirty();
                setForm(f => ({ ...f, isActive: c }));
              }}
              onCancel={closeFormModal}
              onSave={handleSave}
              saving={saving}
            />
          )}
        </div>
      </Modal>
    </>
  );
};

export default HoTroTscdPage;
